func checkServerHeartbeat(cmd *cobra.Command, _ []string) error {
    client, err := api.ClientFromEnvironment()
    if err != nil {
        return err
    }
    if err := client.Heartbeat(cmd.Context()); err != nil {
        if !(strings.Contains(err.Error(), " refused") || 
             strings.Contains(err.Error(), "could not connect")) {
            return err
        }
        if err := startApp(cmd.Context(), client); err != nil {
            return err
        }
        // ... tries to start the server automatically
    }
    return nil
}
```

This function:
- Runs as `PreRunE` before command execution
- Checks if server is responding
- If server is down but can start automatically, it starts it
- Otherwise, returns error

